SELECT 
  FROM er.tn_er_afbr a
 WHERE a.er_id        = #{erId}
   AND a.acft_type_cd = #{acftTypeCd}
   AND NOW() BETWEEN a.use_bgng_dt AND a.use_end_dt

SELECT CASE WHEN COUNT(*) > 0 THEN TRUE ELSE FALSE END
  FROM er.tn_er_afbr
 WHERE er_id        = #{erId}
   AND acft_type_cd = #{acftTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

mapper.update:
UPDATE er.tn_er_afbr
   SET afbr_val         = #{afbrVal},
       afbr_unit        = #{afbrUnit},
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE er_id        = #{erId}
   AND acft_type_cd = #{acftTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE er.tn_er_afbr
   SET use_end_dt        = NOW() - INTERVAL '1 minute',
       last_chg_dt       = NOW(),
       last_chg_user_id  = #{userId}
 WHERE er_id        = #{erId}
   AND acft_type_cd = #{acftTypeCd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
